2	
3	interface Item {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	}
9	
10	interface Damage {
11	  itemType: string;
12	  amount: number;
13	}
14	
15	interface Incident {
16	  cause?: string;
17	  damages: Damage[];
18	}
19	
20	interface Step {
21	  op: string;
22	  items?: Item[];
23	  policy?: number;
24	  incident?: Incident;
25	}
26	
27	interface Customer {
28	  yearsWithMHPCO: number;
29	}
30	
