36	const BASE_PREMIUMS: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const INSURANCE_VALUES: Record<string, number> = {
46	  sword: 1000,
47	  amulet: 600,
48	  staff: 800,
49	  potion: 400,
50	  rune: 250,
51	  moonstone: 250,
52	};
53	
54	const DEDUCTIBLE = 100;
55	const CAP_MULTIPLIER = 2;
56	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
57	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
58	
59	const basePremium = (item: Item): number => {
60	  if (!(item.type in BASE_PREMIUMS)) {
61	    throw new Error(`Unknown item type: ${item.type}`);
62	  }
63	  return BASE_PREMIUMS[item.type];
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const BLOCK_SIZE = 3;
68	const BLOCK_PRICE = 60;
69	
70	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
71	
72	const countByType = (items: Item[]): Record<string, number> =>
73	  items.reduce<Record<string, number>>((counts, item) => {
74	    counts[item.type] = (counts[item.type] ?? 0) + 1;
75	    return counts;
76	  }, {});
77	
78	const componentGroupPremium = (type: string, count: number): number =>
79	  count === BLOCK_SIZE ? BLOCK_PRICE : count * basePremium({ type });
80	
81	const componentsPremium = (components: Item[]): number => {
82	  const counts = countByType(components);
83	  return Object.entries(counts).reduce(
84	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
85	    0,
86	  );
87	};
88	
89	const CURSED_SURCHARGE_RATE = 0.5;
90	const HIGH_ENCHANTMENT_THRESHOLD = 5;
91	const HIGH_ENCHANTMENT_RATE = 0.3;
92	const FIRST_INSURANCE_RATE = 0.1;
93	const LOYALTY_YEARS_THRESHOLD = 2;
94	const LOYALTY_DISCOUNT_RATE = 0.2;
95	const FOLLOWUP_DISCOUNT_RATE = 0.15;
96	
97	const itemSurcharges = (item: Item): number => {
98	  const base = basePremium(item);
99	  let extras = 0;
100	  if (item.cursed) extras += base * CURSED_SURCHARGE_RATE;
101	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
102	    extras += base * HIGH_ENCHANTMENT_RATE;
103	  }
104	  return extras;
105	};
106	
107	interface PremiumBreakdown {
108	  withSurcharges: number;
109	  baseOnly: number;
110	}
111	
112	const itemsPremiumBreakdown = (items: Item[]): PremiumBreakdown => {
113	  const mainItems = items.filter((i) => !isComponent(i));
114	  const componentsTotal = componentsPremium(items.filter(isComponent));
115	  const mainBase = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
116	  const mainSurcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
117	  return {
118	    withSurcharges: mainBase + mainSurcharges + componentsTotal,
119	    baseOnly: mainBase + componentsTotal,
120	  };
121	};
122	
123	const policyModifiers = (
124	  customer: Customer,
125	  policyBase: number,
126	  isFollowUp: boolean,
127	): number => {
128	  let modifiers = policyBase * FIRST_INSURANCE_RATE;
129	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
130	    modifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
131	  }
132	  if (isFollowUp) {
133	    modifiers -= policyBase * FOLLOWUP_DISCOUNT_RATE;
134	  }
135	  return modifiers;
136	};
137	
138	const computeQuotePremium = (
139	  customer: Customer,
140	  items: Item[],
141	  isFollowUp: boolean,
142	): number => {
143	  const { withSurcharges, baseOnly } = itemsPremiumBreakdown(items);
144	  const raw = withSurcharges + policyModifiers(customer, baseOnly, isFollowUp) + PROCESSING_FEE;
145	  return Math.ceil(raw);
146	};
147	
148	interface Policy {
149	  items: Item[];
150	  cap: number;
151	}
152	
153	const policyInsuranceSum = (items: Item[]): number =>
154	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
155	
156	const buildPolicy = (items: Item[]): Policy => ({
157	  items,
158	  cap: policyInsuranceSum(items) * CAP_MULTIPLIER,
159	});
160	
161	const reimbursableAmount = (item: Item, damageAmount: number): number => {
162	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
163	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
164	  }
165	  return damageAmount;
166	};
167	
168	const damagePayout = (item: Item, damageAmount: number): number =>
169	  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;
170	
171	const computeClaim = (
172	  policy: Policy,
173	  incident: Incident,
174	): { payout: number; remainingCap: number } => {
175	  const totalPayout = incident.damages.reduce((sum, damage) => {
176	    const item = policy.items.find((i) => i.type === damage.itemType) as Item;
177	    return sum + damagePayout(item, damage.amount);
178	  }, 0);
179	  return {
180	    payout: Math.floor(totalPayout),
181	    remainingCap: policy.cap - totalPayout,
182	  };
183	};
184	
185	export const runScenario = (scenario: Scenario): unknown => {
186	  const policies: Policy[] = [];
187	  const results = scenario.steps.map((step) => {
188	    if (step.op === "claim") {
189	      return computeClaim(policies[step.policy ?? 0], step.incident as Incident);
190	    }
191	    const items = step.items ?? [];
192	    const isFollowUp = policies.length > 0;
193	    policies.push(buildPolicy(items));
194	    return { premium: computeQuotePremium(scenario.customer, items, isFollowUp) };
195	  });
196	  return { results };
197	};
