const isHighEnchantmentForPayout = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;

const reimbursableAmount = (item: Item, damageAmount: number): number =>
  isHighEnchantmentForPayout(item)
    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
    : damageAmount;

const damagePayout = (item: Item, damageAmount: number): number =>
  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;

const findInsuredItem = (policy: Policy, itemType: string): Item =>
  policy.items.find((i) => i.type === itemType) as Item;

const computeClaim = (
  policy: Policy,
  incident: Incident,
): { payout: number; remainingCap: number } => {
  const totalPayout = incident.damages.reduce(
    (sum, damage) =>
      sum + damagePayout(findInsuredItem(policy, damage.itemType), damage.amount),
    0,
  );
  return {
    payout: Math.floor(totalPayout),
    remainingCap: policy.cap - totalPayout,
